import microcoapy
from microcoapy import coap, resource

# Create a CoAP server instance
server = coap.CoAPServer()

# Define a sensor temperature resource
class TempSensor(resource.Resource):
    def render_get(self, request):
        return b"Temperature: 25C"

temp_resource = TempSensor("sensors/temp")

# Define an actuator light resource
class LightActuator(resource.Resource):
    def render_put(self, request):
        if request.payload == b"on":
            print("Light turned on")
        elif request.payload == b"off":
            print("Light turned off")
        return coap.Code.CONTENT

light_resource = LightActuator("actuators/light")

# Add resources to the server
server.add_resource(temp_resource)
server.add_resource(light_resource)

# Start the CoAP server
try:
    server.listen(5683)  # Listen on port 5683 (CoAP default)
except Exception as e:
    print(f"Error starting CoAP server: {e}")